import React, { useEffect, useRef, useState } from "react";

import { docs, menu } from "constant";

import { Icon } from "components/ui";
import {
  Title,
  Space,
  Indent,
  Section,
  TextItem,
  Container,
  TitleWrap,
  StyledHref,
  TextContent,
  TextItemLink,
  TextItemsWrap,
  TextItemTitle,
} from "./Style";

const TRIAL_YEAR = 2025;
const TRIAL_MONTH = 7;
const TRIAL_DAY = 14;

const MINUTE = 1000 * 60;
const DAY = 1000 * 60 * 60 * 24;

function LegalDefenceSupportWithoutFundraise() {
  const daysCalculatorTimer = useRef<NodeJS.Timeout | null>(null);

  const [daysUntil, setDaysUntil] = useState(0);

  const calculateDaysUntil = () => {
    const now = new Date();
    const targetDate = new Date(
      Date.UTC(TRIAL_YEAR, TRIAL_MONTH - 1, TRIAL_DAY)
    );

    const timeDifference = targetDate.getTime() - now.getTime();

    return timeDifference > 0 ? Math.ceil(timeDifference / DAY) : 0;
  };

  useEffect(() => {
    daysUntilCalculator();

    return () => {
      if (daysCalculatorTimer.current) {
        clearTimeout(daysCalculatorTimer.current);
      }
    };
  }, []);

  const daysUntilCalculator = () => {
    setDaysUntil(calculateDaysUntil());
    daysCalculatorTimer.current = setTimeout(daysUntilCalculator, MINUTE);
  };

  return (
    <Section id="legalDefence">
      <Container>
        <TextItemsWrap>
          <TitleWrap>
            <Icon name="clock" size="xlarge" />
            <Title>Time left until trial: {daysUntil} days</Title>
          </TitleWrap>
          <TextItem>
            <TextItemTitle>
              Legal Defense
              <Indent />
              <Space> </Space>
              Fund Support
            </TextItemTitle>

            <TextContent>
              Trial delay means more legal work: more motions to&nbsp;file, more
              evidence to&nbsp;comb through, more defense strategies
              to&nbsp;incorporate. Recent removal of&nbsp;Tornado Cash sanctions
              also affects attorneys&rsquo; caseload. As&nbsp;such, Roman will
              need at&nbsp;least an&nbsp;additional $1&nbsp;million
              in&nbsp;legal aid. See a&nbsp;more detailed breakdown{" "}
              <StyledHref href={docs.BUDGET}>here!</StyledHref>
            </TextContent>
          </TextItem>
          <TextItemLink to={menu.donate}>
            Donate <Icon name="arrow" rotate="-90deg" size="xlarge" />
          </TextItemLink>
        </TextItemsWrap>
      </Container>
    </Section>
  );
}

export { LegalDefenceSupportWithoutFundraise };
